const body = $input.first().json.body || $input.first().json;

// ── Required fields ───────────────────────────────────────────
const listingId = String(body.listingId || '').trim();
if (!listingId) throw new Error('listingId is required (e.g. LST-2025-0042).');

const address = String(body.address || '').trim();
if (!address) throw new Error('address is required.');

if (!body.fileUrl && !body.filename) {
  throw new Error('Provide fileUrl (remote photo) or filename (binary upload).');
}

// ── File type validation ──────────────────────────────────────
const filename = body.filename ||
  body.fileUrl?.split('?')[0].split('/').pop() ||
  'photo.jpg';
const ext = filename.split('.').pop()?.toLowerCase() || 'jpg';
const allowedExts = ['jpg', 'jpeg', 'png', 'webp', 'heic', 'mp4', 'mov'];
if (!allowedExts.includes(ext)) {
  throw new Error(`File type .${ext} not allowed. Accepted: ${allowedExts.join(', ')}`);
}
const isVideo = ['mp4', 'mov'].includes(ext);

// ── Price normalisation ───────────────────────────────────────
const price = parseFloat(String(body.price || '0').replace(/[^0-9.]/g, '')) || null;

// ── Photo label: allow agent to tag what room this is ─────────
const photoLabel = String(body.photoLabel || '').trim() || null;

// ── Structured filename for CDN ───────────────────────────────
const safeAddress = address.replace(/[^a-zA-Z0-9]/g, '-').slice(0, 40).toLowerCase();
const structuredFilename = `${listingId}_${safeAddress}_${Date.now()}.${ext}`;

const s = v => String(v || '').trim().slice(0, 500);

return [{
  json: {
    listingId,
    address,
    price,
    propertyType: s(body.propertyType) || 'Residential',
    bedrooms: parseInt(body.bedrooms, 10) || null,
    bathrooms: parseFloat(body.bathrooms) || null,
    sqft: parseInt(body.sqft, 10) || null,
    photoLabel,
    isVideo,
    ext,
    filename,
    structuredFilename,
    fileUrl: body.fileUrl || null,
    agentName: s(body.agentName) || 'Unknown Agent',
    agentTelegram: s(body.agentTelegram),
    notes: s(body.notes),
    receivedAt: new Date().toISOString()
  }
}];

const uploadResp = $input.first().json;
const meta = $('Validate Payload').first().json;

const cdnUrl =
  uploadResp.url ||
  uploadResp.link ||
  uploadResp.data?.url ||
  uploadResp.file?.url ||
  uploadResp.shortUrl;

if (!cdnUrl) {
  throw new Error('UploadToURL returned no public URL. Raw: ' + JSON.stringify(uploadResp).slice(0, 300));
}

return [{
  json: {
    ...meta,
    cdnUrl: cdnUrl.replace(/^http:\/\//, 'https://'),
    uploadId: uploadResp.id || uploadResp.data?.id || null,
    fileSizeBytes: uploadResp.size || uploadResp.data?.size || null
  }
}];

