const aiRaw = $input.first().json;
const meta = $('Extract CDN URL').first().json;

// ── Parse Vision response ─────────────────────────────────────
let vision;
try {
  const raw =
    aiRaw.message?.content ||
    aiRaw.choices?.[0]?.message?.content ||
    aiRaw.content ||
    aiRaw.text;
  vision = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('Failed to parse GPT-4o Vision JSON: ' + e.message);
}

if (!vision.roomType) throw new Error('Vision did not return a room type.');

// ── Price formatter ───────────────────────────────────────────
const priceFormatted = meta.price
  ? meta.price.toLocaleString('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 })
  : 'Price on request';

// ── WordPress post title & content ───────────────────────────
const wpTitle = `${meta.propertyType} — ${meta.address}${meta.price ? ' — ' + priceFormatted : ''}`;

const wpContent = [
  `<!-- wp:heading -->\n<h2>${vision.roomType}</h2>\n<!-- /wp:heading -->`,
  `<!-- wp:paragraph -->\n<p>${vision.mlsDescription}</p>\n<!-- /wp:paragraph -->`,
  vision.featureTags?.length
    ? `<!-- wp:list -->\n<ul>${vision.featureTags.map(f => `<li>${f}</li>`).join('')}</ul>\n<!-- /wp:list -->`
    : '',
  `<!-- wp:image -->\n<figure class="wp-block-image">\n<img src="${meta.cdnUrl}" alt="${vision.altText}" />\n<figcaption>${vision.roomType} — ${meta.address}</figcaption>\n</figure>\n<!-- /wp:image -->`,
  meta.notes ? `<!-- wp:paragraph -->\n<p><em>Agent notes: ${meta.notes}</em></p>\n<!-- /wp:paragraph -->` : ''
].filter(Boolean).join('\n\n');

// ── Airtable fields ───────────────────────────────────────────
const airtableRecord = {
  'Listing ID': meta.listingId,
  'Address': meta.address,
  'Price': meta.price,
  'Price Formatted': priceFormatted,
  'Property Type': meta.propertyType,
  'Bedrooms': meta.bedrooms,
  'Bathrooms': meta.bathrooms,
  'Sqft': meta.sqft,
  'Room Type': vision.roomType,
  'Condition Score': vision.conditionScore,
  'Condition Label': vision.conditionLabel,
  'MLS Description': vision.mlsDescription,
  'Feature Tags': (vision.featureTags || []).join(', '),
  'Pricing Signals': (vision.pricingSignals || []).join(', '),
  'Lighting Type': vision.lightingType,
  'Lighting Quality': vision.lightingQuality,
  'Photo URL': meta.cdnUrl,
  'Alt Text': vision.altText,
  'Is Exterior': vision.isExterior || false,
  'Featured Score': vision.featuredImageScore,
  'Renovation Visible': vision.renovationVisible || false,
  'Renovation Age': vision.estimatedRenovationAge || 'Unknown',
  'Agent': meta.agentName,
  'Status': 'Draft',
  'Created At': meta.receivedAt
};

return [{
  json: {
    ...meta,
    // Vision output
    roomType: vision.roomType,
    conditionScore: vision.conditionScore,
    conditionLabel: vision.conditionLabel,
    mlsDescription: vision.mlsDescription,
    featureTags: vision.featureTags || [],
    pricingSignals: vision.pricingSignals || [],
    lightingType: vision.lightingType,
    lightingQuality: vision.lightingQuality,
    altText: vision.altText,
    isExterior: vision.isExterior || false,
    featuredImageScore: vision.featuredImageScore,
    renovationVisible: vision.renovationVisible || false,
    // Computed
    priceFormatted,
    wpTitle,
    wpContent,
    airtableRecord
  }
}];

