// WordPress result is in input[0], Airtable in input[1]
// With multiplex merge both are accessible
const wpResult = $('WordPress - Create Draft Post').first().json;
const atResult = $('Airtable - Create MLS Record').first().json;
const vision = $('Parse Vision & Build Payloads').first().json;

// ── WordPress ─────────────────────────────────────────────────
const wpPostId = wpResult.id || null;
const wpEditUrl = wpPostId
  ? `${$vars.WP_BASE_URL}/wp-admin/post.php?post=${wpPostId}&action=edit`
  : null;
const wpPreviewUrl = wpResult.link || null;

// ── Airtable ──────────────────────────────────────────────────
const airtableRecordId = atResult.id || null;
const airtableUrl = airtableRecordId
  ? `https://airtable.com/${$vars.AIRTABLE_BASE_ID}/${$vars.AIRTABLE_TABLE_NAME}/${airtableRecordId}`
  : null;

return [{
  json: {
    success: true,
    listingId: vision.listingId,
    address: vision.address,
    priceFormatted: vision.priceFormatted,
    propertyType: vision.propertyType,
    agentName: vision.agentName,
    agentTelegram: vision.agentTelegram,
    // Photo
    cdnUrl: vision.cdnUrl,
    roomType: vision.roomType,
    conditionScore: vision.conditionScore,
    conditionLabel: vision.conditionLabel,
    featureTags: vision.featureTags,
    mlsDescription: vision.mlsDescription,
    lightingType: vision.lightingType,
    lightingQuality: vision.lightingQuality,
    isExterior: vision.isExterior,
    // WordPress
    wpPostId,
    wpEditUrl,
    wpPreviewUrl,
    // Airtable
    airtableRecordId,
    airtableUrl,
    // Meta
    publishedAt: new Date().toISOString()
  }
}];

